steps.script:
var fp = PhaseManager.get_current_phase_instance()
fp.awaiting_distraction_grot = true
fp.distraction_grot_pending_unit = "U_BOYZ_E"
fp.resolution_state = {"phase": "awaiting_distraction_grot", "assignments": []}
fp.emit_signal("distraction_grot_available", "U_BOYZ_E", 2)
return true

var d = tree.root.get_node_or_null("DistractionGrotDialog")
if d == null:
	return "NO_DIALOG"
var btns = d.find_children("*", "Button", true, false)
var has_use = false
var has_decline = false
for b in btns:
	var t = String(b.text)
	if t.contains("Distraction Grot"):
		has_use = true
	if t.contains("Decline"):
		has_decline = true
return has_use and has_decline

var d = tree.root.get_node_or_null("DistractionGrotDialog")
if d == null:
	return "NO_DIALOG"
d._on_decline_pressed()
return true
